  ('diplomatic-456f2445-moex-00270', 'diplomatic-456f2445', 'diplomatic-456f2445-moex-112-bf235e6a', 'sub-diplomatic-456f2445-06', NULL, 'single_choice', '臺灣的新聞鮮少登上國際媒體，但是2021年臺灣的「鮭魚之亂」與「太魯閣號出軌」新聞事件被 國際媒體大幅報導。下列那一個國際傳播的術語最適切捕捉此種情況？', '["非平衡之新聞流通", "新聞價值", "新聞形象", "新聞框架"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:20+00:00", "source_pdf_sha1": "39f0d362903b", "answer_pdf_sha1": "2a0d88fd0b3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-西班牙文組"}'::jsonb, NULL),
